mapper.select:
SELECT r.id, r.target_type AS targetType, r.post_id AS targetId, r.reporter_id AS userId, u.login_id AS reporterName, r.reason_type AS reasonType, r.content, r.status, r.created_at AS createdAt, f.file_path AS filePath FROM report r LEFT JOIN user u ON r.reporter_id = u.id LEFT JOIN file f ON f.target_id = r.id AND f.target_type = 'REPORT'
AND r.status = #{status}
ORDER BY r.created_at DESC
